unit lipdecide;

interface

uses globals;

procedure DECIDE;
function REALCOMPARE(A, B: real): COMPTYPE;

implementation

function REALCOMPARE(A, B: real): COMPTYPE;
var
  diff, maxVal: real;
begin
  if A = B then
    REALCOMPARE := EQ
  else begin
    maxVal := Abs(A);
    if Abs(B) > maxVal then
      maxVal := Abs(B);
    if maxVal = 0 then
      REALCOMPARE := EQ
    else begin
      diff := Abs(A - B);
      if diff < maxVal * 5e-6 then
        REALCOMPARE := EQ
      else if A < B then
        REALCOMPARE := LT
      else
        REALCOMPARE := GT;
    end;
  end;
end;

function Dist(i, j: integer): real;
begin
  Dist := Sqrt(Sqr(X[i] - X[j]) + Sqr(Y[i] - Y[j]));
end;

function TriangleArea(i, j, k: integer): real;
begin
  TriangleArea := 0.5 * Abs(X[i] * (Y[j] - Y[k]) + X[j] * (Y[k] - Y[i]) + X[k] * (Y[i] - Y[j]));
end;

function MyArcCos(x: real): real;
begin
  if x >= 1 then
    MyArcCos := 0
  else if x <= -1 then
    MyArcCos := PI
  else
    MyArcCos := PI / 2 - ArcTan(x / Sqrt(1 - x * x));
end;

function AngleAtVertex(i, j, k: integer): real;
var
  v1x, v1y, v2x, v2y, dot, mag1, mag2, cosAngle: real;
begin
  v1x := X[i] - X[j];
  v1y := Y[i] - Y[j];
  v2x := X[k] - X[j];
  v2y := Y[k] - Y[j];
  mag1 := Sqrt(Sqr(v1x) + Sqr(v1y));
  mag2 := Sqrt(Sqr(v2x) + Sqr(v2y));
  dot := v1x * v2x + v1y * v2y;
  cosAngle := dot / (mag1 * mag2);
  if cosAngle > 1 then cosAngle := 1;
  if cosAngle < -1 then cosAngle := -1;
  AngleAtVertex := MyArcCos(cosAngle);
end;

function MinEnclosingCircleRadius(i, j, k: integer): real;
var
  a, b, c, area, maxSide: real;
begin
  a := Dist(i, j);
  b := Dist(j, k);
  c := Dist(i, k);
  area := TriangleArea(i, j, k);

  if REALCOMPARE(area, 0) = EQ then
  begin
    maxSide := a;
    if REALCOMPARE(b, maxSide) = GT then maxSide := b;
    if REALCOMPARE(c, maxSide) = GT then maxSide := c;
    MinEnclosingCircleRadius := maxSide / 2;
  end
  else
  begin
    if (REALCOMPARE(Sqr(c), Sqr(a) + Sqr(b)) <> LT) or
       (REALCOMPARE(Sqr(b), Sqr(a) + Sqr(c)) <> LT) or
       (REALCOMPARE(Sqr(a), Sqr(b) + Sqr(c)) <> LT) then
    begin
      maxSide := a;
      if REALCOMPARE(b, maxSide) = GT then maxSide := b;
      if REALCOMPARE(c, maxSide) = GT then maxSide := c;
      MinEnclosingCircleRadius := maxSide / 2;
    end
    else
      MinEnclosingCircleRadius := a * b * c / (4 * area);
  end;
end;

function PointToLineDist(px, py, ax, ay, bx, by: real): real;
var
  dx, dy, cross: real;
begin
  dx := bx - ax;
  dy := by - ay;
  if REALCOMPARE(Sqr(dx) + Sqr(dy), 0) = EQ then
    PointToLineDist := Sqrt(Sqr(px - ax) + Sqr(py - ay))
  else
  begin
    cross := Abs(dx * (py - ay) - dy * (px - ax));
    PointToLineDist := cross / Sqrt(Sqr(dx) + Sqr(dy));
  end;
end;

function GetQuadrant(i: integer): integer;
var
  xComp, yComp: COMPTYPE;
begin
  xComp := REALCOMPARE(X[i], 0);
  yComp := REALCOMPARE(Y[i], 0);

  if (xComp = GT) or (xComp = EQ) then
  begin
    if (yComp = GT) or (yComp = EQ) then
      GetQuadrant := 1
    else
      GetQuadrant := 4;
  end
  else
  begin
    if (yComp = GT) or (yComp = EQ) then
      GetQuadrant := 2
    else
      GetQuadrant := 3;
  end;
end;

procedure DECIDE;
var
  i, j, k, start, p, count: integer;
  found, hasGreater, hasLess, rowAllTrue: boolean;
  quadSet: set of 1..4;
begin
  for i := 1 to 15 do
    CMV[i] := false;

  { LIC 1: Two consecutive points distance > LENGTH1 }
  for i := 1 to NUMPOINTS - 1 do
    if REALCOMPARE(Dist(i, i+1), PARAMETERS.LENGTH1) = GT then
    begin
      CMV[1] := true;
      Break;
    end;

  { LIC 2: Three consecutive points cannot be contained in circle of radius RADIUS1 }
  for i := 1 to NUMPOINTS - 2 do
    if REALCOMPARE(MinEnclosingCircleRadius(i, i+1, i+2), PARAMETERS.RADIUS1) = GT then
    begin
      CMV[2] := true;
      Break;
    end;

  { LIC 3: Three consecutive points form angle outside (PI-EPSILON, PI+EPSILON) }
  for i := 1 to NUMPOINTS - 2 do
  begin
    if (REALCOMPARE(X[i], X[i+1]) <> EQ) or (REALCOMPARE(Y[i], Y[i+1]) <> EQ) then
      if (REALCOMPARE(X[i+2], X[i+1]) <> EQ) or (REALCOMPARE(Y[i+2], Y[i+1]) <> EQ) then
      begin
        if REALCOMPARE(AngleAtVertex(i, i+1, i+2), PI - PARAMETERS.EPSILON) = LT then
        begin
          CMV[3] := true;
          Break;
        end;
        if REALCOMPARE(AngleAtVertex(i, i+1, i+2), PI + PARAMETERS.EPSILON) = GT then
        begin
          CMV[3] := true;
          Break;
        end;
      end;
  end;

  { LIC 4: Three consecutive points form triangle with area > AREA1 }
  for i := 1 to NUMPOINTS - 2 do
    if REALCOMPARE(TriangleArea(i, i+1, i+2), PARAMETERS.AREA1) = GT then
    begin
      CMV[4] := true;
      Break;
    end;

  { LIC 5: Q_PTS consecutive points lie in more than QUADS quadrants }
  for start := 1 to NUMPOINTS - PARAMETERS.Q_PTS + 1 do
  begin
    quadSet := [];
    for k := 0 to PARAMETERS.Q_PTS - 1 do
      quadSet := quadSet + [GetQuadrant(start + k)];
    count := 0;
    for j := 1 to 4 do
      if j in quadSet then
        Inc(count);
    if count > PARAMETERS.QUADS then
    begin
      CMV[5] := true;
      Break;
    end;
  end;

  { LIC 6: Two consecutive points where X[j] - X[i] < 0 }
  for i := 1 to NUMPOINTS - 1 do
    if REALCOMPARE(X[i+1] - X[i], 0) = LT then
    begin
      CMV[6] := true;
      Break;
    end;

  { LIC 7: N_PTS consecutive points, one point distance > DIST from line }
  for start := 1 to NUMPOINTS - PARAMETERS.N_PTS + 1 do
  begin
    found := false;
    for p := start + 1 to start + PARAMETERS.N_PTS - 2 do
      if REALCOMPARE(PointToLineDist(X[p], Y[p], X[start], Y[start],
         X[start + PARAMETERS.N_PTS - 1], Y[start + PARAMETERS.N_PTS - 1]),
         PARAMETERS.DIST) = GT then
      begin
        found := true;
        Break;
      end;
    if found then
    begin
      CMV[7] := true;
      Break;
    end;
  end;

  { LIC 8: Two points separated by K_PTS, distance > LENGTH1 }
  for i := 1 to NUMPOINTS - PARAMETERS.K_PTS - 1 do
    if REALCOMPARE(Dist(i, i + PARAMETERS.K_PTS + 1), PARAMETERS.LENGTH1) = GT then
    begin
      CMV[8] := true;
      Break;
    end;

  { LIC 9: Three points separated by A_PTS and B_PTS, cannot be contained in circle of radius RADIUS1 }
  for i := 1 to NUMPOINTS - PARAMETERS.A_PTS - PARAMETERS.B_PTS - 2 do
    if REALCOMPARE(MinEnclosingCircleRadius(i, i + PARAMETERS.A_PTS + 1,
       i + PARAMETERS.A_PTS + PARAMETERS.B_PTS + 2), PARAMETERS.RADIUS1) = GT then
    begin
      CMV[9] := true;
      Break;
    end;

  { LIC 10: Three points separated by C_PTS and D_PTS, angle outside (PI-EPSILON, PI+EPSILON) }
  for i := 1 to NUMPOINTS - PARAMETERS.C_PTS - PARAMETERS.D_PTS - 2 do
  begin
    j := i + PARAMETERS.C_PTS + 1;
    k := i + PARAMETERS.C_PTS + PARAMETERS.D_PTS + 2;
    if (REALCOMPARE(X[i], X[j]) <> EQ) or (REALCOMPARE(Y[i], Y[j]) <> EQ) then
      if (REALCOMPARE(X[k], X[j]) <> EQ) or (REALCOMPARE(Y[k], Y[j]) <> EQ) then
      begin
        if REALCOMPARE(AngleAtVertex(i, j, k), PI - PARAMETERS.EPSILON) = LT then
        begin
          CMV[10] := true;
          Break;
        end;
        if REALCOMPARE(AngleAtVertex(i, j, k), PI + PARAMETERS.EPSILON) = GT then
        begin
          CMV[10] := true;
          Break;
        end;
      end;
  end;

  { LIC 11: Three points separated by E_PTS and F_PTS, triangle area > AREA1 }
  for i := 1 to NUMPOINTS - PARAMETERS.E_PTS - PARAMETERS.F_PTS - 2 do
    if REALCOMPARE(TriangleArea(i, i + PARAMETERS.E_PTS + 1,
       i + PARAMETERS.E_PTS + PARAMETERS.F_PTS + 2), PARAMETERS.AREA1) = GT then
    begin
      CMV[11] := true;
      Break;
    end;

  { LIC 12: Two points separated by G_PTS, X[j] - X[i] < 0 }
  for i := 1 to NUMPOINTS - PARAMETERS.G_PTS - 1 do
    if REALCOMPARE(X[i + PARAMETERS.G_PTS + 1] - X[i], 0) = LT then
    begin
      CMV[12] := true;
      Break;
    end;

  { LIC 13: Two parts - distance > LENGTH1 and distance < LENGTH2, both with K_PTS separation }
  hasGreater := false;
  hasLess := false;
  for i := 1 to NUMPOINTS - PARAMETERS.K_PTS - 1 do
  begin
    if REALCOMPARE(Dist(i, i + PARAMETERS.K_PTS + 1), PARAMETERS.LENGTH1) = GT then
      hasGreater := true;
    if REALCOMPARE(Dist(i, i + PARAMETERS.K_PTS + 1), PARAMETERS.LENGTH2) = LT then
      hasLess := true;
  end;
  CMV[13] := hasGreater and hasLess;

  { LIC 14: Two parts - cannot fit in RADIUS1 and can fit in RADIUS2 }
  hasGreater := false;
  hasLess := false;
  for i := 1 to NUMPOINTS - PARAMETERS.A_PTS - PARAMETERS.B_PTS - 2 do
  begin
    if REALCOMPARE(MinEnclosingCircleRadius(i, i + PARAMETERS.A_PTS + 1,
       i + PARAMETERS.A_PTS + PARAMETERS.B_PTS + 2), PARAMETERS.RADIUS1) = GT then
      hasGreater := true;
    if REALCOMPARE(MinEnclosingCircleRadius(i, i + PARAMETERS.A_PTS + 1,
       i + PARAMETERS.A_PTS + PARAMETERS.B_PTS + 2), PARAMETERS.RADIUS2) <> GT then
      hasLess := true;
  end;
  CMV[14] := hasGreater and hasLess;

  { LIC 15: Two parts - area > AREA1 and area < AREA2 }
  hasGreater := false;
  hasLess := false;
  for i := 1 to NUMPOINTS - PARAMETERS.E_PTS - PARAMETERS.F_PTS - 2 do
  begin
    if REALCOMPARE(TriangleArea(i, i + PARAMETERS.E_PTS + 1,
       i + PARAMETERS.E_PTS + PARAMETERS.F_PTS + 2), PARAMETERS.AREA1) = GT then
      hasGreater := true;
    if REALCOMPARE(TriangleArea(i, i + PARAMETERS.E_PTS + 1,
       i + PARAMETERS.E_PTS + PARAMETERS.F_PTS + 2), PARAMETERS.AREA2) = LT then
      hasLess := true;
  end;
  CMV[15] := hasGreater and hasLess;

  { PUM off-diagonal elements }
  for i := 1 to 15 do
    for j := 1 to 15 do
      if i <> j then
        case LCM[i, j] of
          NOTUSED: PUM[i, j] := true;
          ORR: PUM[i, j] := CMV[i] or CMV[j];
          ANDD: PUM[i, j] := CMV[i] and CMV[j];
        end;

  { FUV }
  for i := 1 to 15 do
  begin
    if not PUM[i, i] then
      FUV[i] := true
    else
    begin
      rowAllTrue := true;
      for j := 1 to 15 do
        if not PUM[i, j] then
        begin
          rowAllTrue := false;
          Break;
        end;
      FUV[i] := rowAllTrue;
    end;
  end;

  { LAUNCH decision }
  LAUNCH := true;
  for i := 1 to 15 do
    if not FUV[i] then
    begin
      LAUNCH := false;
      Break;
    end;
end;

end.
